class Node:
    def __init__(self, key, value):
        self.key = key
        self.value = value
        self.next = None

class HashTableChaining:
    def __init__(self, size=10):
        self.size = size
        self.table = [None] * self.size

    def _hash(self, key):
        return hash(key) % self.size

    def insert(self, key, value):
        index = self._hash(key)
        new_node = Node(key, value)

        if self.table[index] is None:
            self.table[index] = new_node
        else:
            current = self.table[index]
            while current.next:
                if current.key == key:
                    current.value = value
                    return
                current = current.next
            if current.key == key:
                current.value = value
            else:
                current.next = new_node

    def search(self, key):
        index = self._hash(key)
        current = self.table[index]
        while current:
            if current.key == key:
                return current.value
            current = current.next
        return None

    def delete(self, key):
        index = self._hash(key)
        current = self.table[index]
        prev = None
        while current:
            if current.key == key:
                if prev:
                    prev.next = current.next
                else:
                    self.table[index] = current.next
                return True
            prev = current
            current = current.next
        return False

# Demonstration
ht = HashTableChaining(7)
ht.insert("apple", 100)
ht.insert("banana", 200)
ht.insert("grape", 300)
ht.insert("mango", 400)

print("Search 'apple':", ht.search("apple"))
print("Search 'grape':", ht.search("grape"))
ht.delete("banana")
print("After delete, search 'banana':", ht.search("banana"))

class HashTableLinearProbing:
    def __init__(self, size=10):
        self.size = size
        self.table = [None] * self.size
        self.count = 0

    def _hash(self, key):
        return hash(key) % self.size

    def _probe(self, index, i):
        return (index + i) % self.size

    def insert(self, key, value):
        if self.count >= self.size:
            print("Table is full")
            return

        index = self._hash(key)

        for i in range(self.size):
            probe_index = self._probe(index, i)

            if self.table[probe_index] is None:
                self.table[probe_index] = (key, value)
                self.count += 1
                return True
            elif self.table[probe_index][0] == key:
                self.table[probe_index] = (key, value)
                return True

        print("Could not insert", key)
        return False

    def search(self, key):
        index = self._hash(key)

        for i in range(self.size):
            probe_index = self._probe(index, i)

            if self.table[probe_index] is None:
                return None

            if self.table[probe_index][0] == key:
                return self.table[probe_index][1]

        return None

    def delete(self, key):
        index = self._hash(key)

        for i in range(self.size):
            probe_index = self._probe(index, i)

            if self.table[probe_index] is None:
                return False

            if self.table[probe_index][0] == key:
                self.table[probe_index] = None
                self.count -= 1
                return True

        return False

# Demonstration
ht = HashTableLinearProbing(7)
keys = ["cat", "dog", "elephant", "fish", "bird", "lion"]
values = [1, 2, 3, 4, 5, 6]

for k, v in zip(keys, values):
    ht.insert(k, v)

print("Search 'dog':", ht.search("dog"))
print("Search 'fish':", ht.search("fish"))
ht.delete("dog")
print("After delete, search 'dog':", ht.search("dog"))
print("Table contents:", ht.table)

class HashTableDoubleHashing:
    def __init__(self, size=10):
        self.size = size
        self.table = [None] * self.size
        self.count = 0

    def _hash1(self, key):
        return hash(key) % self.size

    def _hash2(self, key):
        # Secondary hash function must be non-zero and different from hash1
        prime = self._get_prime_less_than_size()
        return prime - (hash(key) % prime)

    def _get_prime_less_than_size(self):
        for p in range(self.size - 1, 1, -1):
            if self._is_prime(p):
                return p
        return 1

    def _is_prime(self, n):
        if n < 2:
            return False
        for i in range(2, int(n ** 0.5) + 1):
            if n % i == 0:
                return False
        return True

    def _probe(self, index, i, key):
        h2 = self._hash2(key)
        if h2 == 0:
            h2 = 1  # Ensure non-zero
        return (index + i * h2) % self.size

    def insert(self, key, value):
        if self.count >= self.size:
            print("Table is full")
            return False

        index = self._hash1(key)

        for i in range(self.size):
            probe_index = self._probe(index, i, key)

            if self.table[probe_index] is None:
                self.table[probe_index] = (key, value)
                self.count += 1
                return True
            elif self.table[probe_index][0] == key:
                self.table[probe_index] = (key, value)
                return True

        return False

    def search(self, key):
        index = self._hash1(key)

        for i in range(self.size):
            probe_index = self._probe(index, i, key)

            if self.table[probe_index] is None:
                return None

            if self.table[probe_index][0] == key:
                return self.table[probe_index][1]

        return None

# Demonstration
ht = HashTableDoubleHashing(11)
keys = ["apple", "banana", "cherry", "date", "elderberry", "fig", "grape"]
values = [10, 20, 30, 40, 50, 60, 70]

print("Inserting elements:")
for k, v in zip(keys, values):
    result = ht.insert(k, v)
    print(f"  {k}: {'success' if result else 'failed'}")

print("\nSearching elements:")
for key in ["apple", "cherry", "grape", "watermelon"]:
    result = ht.search(key)
    print(f"  {key}: {result if result else 'not found'}")

print("\nHash table:")
for i, item in enumerate(ht.table):
    print(f"  Index {i}: {item}")
